INSERT INTO `v1_5575af91dfccbedb79500c702598a755925f1d7ed68dd8fbb1ba8e774c0bf7fe` VALUES ("bgm_M199_juke", "2030/12/31 15:00:00", 1001, "お兄ちゃん争奪！\nどっちのチョコがおいしいでSHOW", "", "2020-02-15 15:00:00", "2030/12/31 15:00:00", 10000, "愛情たっぷりのチョコレートケー\nキを完成させよう！\n超キュートなタップゲーム！", "bgm_M199", 1002);
